sql:
SELECT DISTINCT u.username, u.role
FROM users u
JOIN awc_cases ac ON u.user_id = ac.user_id;

SELECT user_id, COUNT(service_id) AS avg_services_distributed
FROM services_distributed
GROUP BY user_id;

SELECT COUNT(*)
FROM anc_visits
WHERE visit_date LIKE '%-12-%';

SELECT awc_id, COUNT(*) AS num_services
FROM services_distributed
GROUP BY awc_id;

SELECT facility_id, month, COUNT(*) as total_cases
FROM awc_cases
GROUP BY facility_id, month;

SELECT COUNT(DISTINCT awc_id) AS recent_anemia_assessments
FROM anemia_status
WHERE (julianday('now') - julianday(status_date)) <= 7;

SELECT COUNT(*) 
FROM awc_cases
WHERE trimester = 3;

SELECT awc_id, month, age_in_months, ccs_status, open_in_month, alive_in_month, trimester, registration_date, last_visit_date 
FROM awc_cases 
WHERE facility_id = 'SPECIFIC_FACILITY_ID';

SELECT *
FROM services_distributed
WHERE user_id = 'desired_user_id';

external_knowledge:
- Medical gardeners refer to healthcare providers; 
- Bloom refers to cases or instances of patient care; 
- Diversity of blooms refers to the variety of services provided; 
- Nectar of iron-folic acid represents the consumption of IFA doses; 
- A hundred cups symbolizes a threshold of 100 IFA doses; 
- Blooming hospitals refer to health facilities with 'hospital' in their names.

- "saplings" metaphorically refers to young women/mothers;
- "tender years" refers to being younger than 20 years old (240 months);
- "finding nourishment in the iron-folic acid supplements" means that they are using iron-folic acid supplements;
- "garden's registry" symbolizes the database records.

sql:
SELECT COUNT(DISTINCT user_id)
FROM awc_cases
WHERE facility_id = 'your_facility_id';

SELECT AVG(session_count) AS average_sessions_per_month
FROM (
  SELECT STRFTIME('%Y-%m', session_date) AS month, COUNT(*) AS session_count
  FROM counseling_sessions
  GROUP BY month
);

SELECT COUNT(DISTINCT user_id) AS total_users
FROM awc_cases
WHERE strftime('%Y-%m', registration_date) = '2020-09';

SELECT service_date, num_rations_distributed
FROM services_distributed
WHERE num_rations_distributed > 5;
